// Extract service info from request
const input = $input.first().json;

return [{
  json: {
    service_id: input.service_id || 'google_calendar',
    action: input.action || 'check', // 'check', 'record_success', 'record_failure'
    error_message: input.error_message || null,
    metadata: input.metadata || {}
  }
}];

// Circuit is CLOSED - service is healthy
const state = $input.first().json;

return [{
  json: {
    allowed: true,
    circuit_state: 'closed',
    message: 'Service is healthy - requests allowed',
    failure_count: state.failure_count || 0,
    service_id: state.service_id
  }
}];

// Circuit is OPEN - check if timeout has passed
const state = $input.first().json;
const now = new Date();
const openedAt = state.opened_at ? new Date(state.opened_at) : null;
const timeoutSeconds = state.timeout_seconds || 300;

let shouldTryHalfOpen = false;
let timeUntilRetry = 0;

if (openedAt) {
  const elapsedSeconds = (now - openedAt) / 1000;
  if (elapsedSeconds >= timeoutSeconds) {
    shouldTryHalfOpen = true;
  } else {
    timeUntilRetry = Math.ceil(timeoutSeconds - elapsedSeconds);
  }
}

return [{
  json: {
    ...state,
    should_try_half_open: shouldTryHalfOpen,
    time_until_retry_seconds: timeUntilRetry,
    elapsed_since_open: openedAt ? Math.floor((now - openedAt) / 1000) : null
  }
}];

// Return circuit breaker status
const state = $input.first().json;

return [{
  json: {
    allowed: state.state === 'half-open' || state.should_try_half_open,
    circuit_state: state.state === 'half-open' ? 'half-open' : 'open',
    message: state.state === 'half-open' 
      ? 'Circuit in half-open state - test request allowed' 
      : `Circuit OPEN - retry in ${state.time_until_retry_seconds || 'unknown'}s`,
    service_id: state.service_id,
    failure_count: state.failure_count || 0,
    opened_at: state.opened_at,
    time_until_retry_seconds: state.time_until_retry_seconds || 0
  }
}];

// Circuit is OPEN and timeout not passed
const state = $input.first().json;

return [{
  json: {
    allowed: false,
    circuit_state: 'open',
    message: `Circuit breaker OPEN - service unavailable. Retry in ${state.time_until_retry_seconds || 'unknown'} seconds`,
    service_id: state.service_id,
    retry_after_seconds: state.time_until_retry_seconds || 300,
    failure_count: state.failure_count || 0
  }
}];

// Standard Contract Output
const cbResult = $('Return Closed State').first()?.json || 
                 $('Return Open State').first()?.json || 
                 $('Return Blocked').first()?.json;

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: cbResult,
    _meta: {
      source: 'CB_GCal_Circuit_BreakER',
      timestamp: new Date().toISOString(),
      version: '1.0.0'
    }
  }
}];

// Record success or failure
const input = $input.first().json;
const result = input.success ? 'success' : 'failure';

return [{
  json: {
    service_id: input.service_id || 'google_calendar',
    result: result,
    error_message: input.error_message || null,
    metadata: input.metadata || {}
  }
}];

// Return result of record operation
const state = $input.first().json;

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      recorded: true,
      service_id: state.service_id,
      new_state: state.state,
      failure_count: state.failure_count,
      success_count: state.success_count,
      message: `Recorded ${state.failure_count > 0 ? 'failure' : 'success'} for ${state.service_id}`
    },
    _meta: {
      source: 'CB_GCal_Circuit_BreakER',
      timestamp: new Date().toISOString(),
      version: '1.0.0'
    }
  }
}];
